:root {
  /* Colors NovaVision */
  --chat--color-primary: #16b0f8;
  --chat--color-primary-shade-50: #109dd8;
  --chat--color-primary-shade-100: #0677a5;
  --chat--color-secondary: #25d366;
  --chat--color-secondary-shade-50: #1aaf50;
  --chat--color-white: #ffffff;
  --chat--color-light: #151d24;
  --chat--color-light-shade-50: #101820;
  --chat--color-light-shade-100: #28374a;
  --chat--color-medium: #222c35;
  --chat--color-dark: #121d27;
  --chat--color-disabled: #666f77;
  --chat--color-typing: #34e1eb;

  /* Base Layout */
  --chat--spacing: 1.15rem;
  --chat--border-radius: 1.5rem;
  --chat--transition-duration: 0.22s;
  --chat--font-family: "Inter", "Segoe UI", "Roboto", Arial, sans-serif;

  /* Window */
  --chat--window--width: 420px;
  --chat--window--height: 680px;
  --chat--window--bottom: 2.4rem;
  --chat--window--right: 2.4rem;
  --chat--window--z-index: 9999;
  --chat--window--border: 1px solid rgba(40,55,74,0.6);
  --chat--window--border-radius: 1.6rem;
  --chat--window--margin-bottom: var(--chat--spacing);

  /* Header */
  --chat--header-height: auto;
  --chat--header--padding: 1rem 1.4rem;
  --chat--header--background: linear-gradient(135deg, #0d1520 0%, #162232 100%);
  --chat--header--color: #e6f7ff;
  --chat--header--border-bottom: 1px solid rgba(22,176,248,0.15);
  --chat--heading--font-size: 1.25rem;
  --chat--subtitle--font-size: 0.88rem;
  --chat--subtitle--line-height: 1.5;

  /* Messages */
  --chat--message--font-size: 0.94rem;
  --chat--message--padding: 0.75rem 1rem;
  --chat--message--border-radius: 1.2rem;
  --chat--message-line-height: 1.6;
  --chat--message--margin-bottom: 0.5rem;
  --chat--message--bot--background: rgba(22,176,248,0.08);
  --chat--message--bot--color: #d0eafc;
  --chat--message--bot--border: 1px solid rgba(22,176,248,0.12);
  --chat--message--user--background: linear-gradient(135deg, #16b0f8 0%, #0d8fd4 100%);
  --chat--message--user--color: #fff;
  --chat--message--user--border: none;
  --chat--message--pre--background: #0a1219;
  --chat--messages-list--padding: 1.2rem 0.8rem 0.6rem 0.8rem;

  /* Toggle Button */
  --chat--toggle--size: 64px;
  --chat--toggle--width: var(--chat--toggle--size);
  --chat--toggle--height: var(--chat--toggle--size);
  --chat--toggle--border-radius: 50%;
  --chat--toggle--background: linear-gradient(135deg, #16b0f8 0%, #0d8fd4 100%);
  --chat--toggle--hover--background: #109dd8;
  --chat--toggle--active--background: #0677a5;
  --chat--toggle--color: #fff;
  box-shadow: 0 4px 24px rgba(22,176,248,0.35);

  /* Input */
  --chat--textarea--height: 44px;
  --chat--textarea--max-height: 12rem;
  --chat--input--font-size: 0.95rem;
  --chat--input--border: 1.5px solid rgba(40,55,74,0.5);
  --chat--input--border-radius: 1rem;
  --chat--input--padding: 0.7rem 1rem;
  --chat--input--background: rgba(16,24,32,0.8);
  --chat--input--text-color: #f0f6ff;
  --chat--input--line-height: 1.5;
  --chat--input--placeholder--font-size: 0.92rem;
  --chat--input--border-active: 1.5px solid #16b0f8;
  --chat--input--left--panel--width: 2rem;

  /* Buttons */
  --chat--button--color: #fff;
  --chat--button--background: #16b0f8;
  --chat--button--padding: 0.65rem 1.2rem;
  --chat--button--border-radius: 0.9rem;
  --chat--button--hover--color: #fff;
  --chat--button--hover--background: #109dd8;
  --chat--close--button--color-hover: #16b0f8;

  /* Send/File Buttons */
  --chat--input--send--button--background: transparent;
  --chat--input--send--button--color: #16b0f8;
  --chat--input--send--button--background-hover: rgba(22,176,248,0.15);
  --chat--input--send--button--color-hover: #fff;
  --chat--input--file--button--background: transparent;
  --chat--input--file--button--color: #16b0f8;
  --chat--input--file--button--background-hover: rgba(22,176,248,0.1);
  --chat--input--file--button--color-hover: #109dd8;
  --chat--files-spacing: 0.27rem;


  /* Input Container */
  --chat--input--container--background: rgba(16,24,32,0.6);
  --chat--input--container--border: 1px solid rgba(22,176,248,0.15);
  --chat--input--container--border-radius: 1.2rem;
  --chat--input--container--padding: 0.5rem 0.7rem;

  /* Body & Footer */
  --chat--body--background: #0d1520;
  --chat--footer--background: rgba(18,29,39,0.95);
  --chat--footer--color: #c5e4fb;
}

/* ── Keyframes ── */
@keyframes nv-msg-in {
  from { opacity: 0; transform: translateY(12px) scale(0.97); }
  to { opacity: 1; transform: translateY(0) scale(1); }
}
@keyframes nv-fade-in {
  from { opacity: 0; }
  to { opacity: 1; }
}
@keyframes nv-pulse-ring {
  0% { box-shadow: 0 0 0 0 rgba(22,176,248,0.4); }
  70% { box-shadow: 0 0 0 8px rgba(22,176,248,0); }
  100% { box-shadow: 0 0 0 0 rgba(22,176,248,0); }
}

/* ── Window ── */
.chat-wrapper {
  box-shadow: 0 16px 48px rgba(0,0,0,0.45), 0 0 0 1px rgba(22,176,248,0.08);
  animation: nv-fade-in 0.3s ease-out;
}

/* ── Header ── */
.chat-header {
  border-bottom: 1px solid rgba(22,176,248,0.12) !important;
  padding-bottom: 0.8rem;
}
.chat-header p {
  opacity: 0.6;
  font-size: 0.82rem;
  margin-top: 0.15rem;
  letter-spacing: 0.02em;
}

/* ── Heading with Logo ── */
.chat-heading {
  position: relative;
  padding-left: 3.6rem;
  display: flex;
  align-items: center;
  font-weight: 700;
  font-size: 1.15rem;
  letter-spacing: -0.01em;
}
.chat-heading h1 {
  font-size: inherit;
  font-weight: inherit;
  margin: 0;
}
.chat-heading::before {
  content: "";
  position: absolute;
  left: 0;
  top: 50%;
  transform: translateY(-50%);
  width: 3rem;
  height: 3rem;
  background-image: url('https://novavision.lat/logo/logo.png');
  background-size: contain;
  background-repeat: no-repeat;
  background-position: center;
  border-radius: 0.6rem;
  animation: nv-pulse-ring 2.5s ease-in-out infinite;
}

/* ── Messages ── */
.chat-messages-list {
  scroll-behavior: smooth;
}
.chat-messages-list::-webkit-scrollbar {
  width: 5px;
}
.chat-messages-list::-webkit-scrollbar-track {
  background: transparent;
}
.chat-messages-list::-webkit-scrollbar-thumb {
  background: rgba(22,176,248,0.2);
  border-radius: 10px;
}
.chat-messages-list::-webkit-scrollbar-thumb:hover {
  background: rgba(22,176,248,0.35);
}

/* Message entrance animation */
.chat-message {
  animation: nv-msg-in 0.35s cubic-bezier(0.22, 0.68, 0.32, 1) both;
  max-width: 88%;
  word-break: break-word;
}

/* Bot bubble - tail left */
.chat-message-from-bot .chat-message-markdown {
  border-radius: 1.2rem 1.2rem 1.2rem 0.25rem;
}

/* User bubble - tail right */
.chat-message-from-user .chat-message-markdown {
  border-radius: 1.2rem 1.2rem 0.25rem 1.2rem;
}

.chat-message-markdown {
  font-size: 0.92rem;
  line-height: 1.65;
}
.chat-message-markdown a {
  color: #5bc8ff;
  text-decoration: underline;
  text-underline-offset: 2px;
  transition: color 0.15s;
}
.chat-message-markdown a:hover {
  color: #fff;
}
.chat-message-markdown p {
  margin: 0 0 0.4em 0;
}
.chat-message-markdown p:last-child {
  margin-bottom: 0;
}


/* ── Input container (wrapper) ── */
.chat-inputs {
  background: rgba(16,24,32,0.6) !important;
  border: 1px solid rgba(22,176,248,0.15) !important;
  border-radius: 1.2rem !important;
  padding: 0.5rem 0.7rem !important;
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
  transition: border-color 0.2s ease;
}
.chat-inputs:focus-within {
  border-color: rgba(22,176,248,0.4) !important;
  box-shadow: 0 0 0 3px rgba(22,176,248,0.08);
}

/* ── .chat-input outer wrapper ── */
.chat-input {
  background: transparent !important;
  border: none !important;
  padding: 0.6rem 0.8rem !important;
}

/* ── Input area ── */
.chat-input textarea {
  transition: border-color 0.2s, box-shadow 0.2s;
}
.chat-input textarea:focus {
  box-shadow: 0 0 0 3px rgba(22,176,248,0.15);
}
.chat-input textarea::placeholder {
  color: rgba(197,228,251,0.35);
  font-style: italic;
}

/* Send button */
.chat-input-send-button {
  border-radius: 50% !important;
  width: 38px;
  height: 38px;
  transition: transform 0.15s, background 0.2s, color 0.2s;
}
.chat-input-send-button:not(:disabled):hover {
  transform: scale(1.1);
}
.chat-input-send-button:not(:disabled):active {
  transform: scale(0.95);
}

/* ── Footer ── */
.chat-footer {
  border-top: 1px solid rgba(22,176,248,0.08);
  padding-top: 0.5rem;
}

/* ── Responsive ── */
@media (max-width: 750px) {
  :root {
    --chat--window--width: 98vw;
    --chat--window--height: 95vh;
    --chat--window--bottom: 0.5rem;
    --chat--window--right: 0.5rem;
    --chat--window--border-radius: 1.2rem;
    --chat--header--padding: 0.9rem 0.7rem;
    --chat--messages-list--padding: 1rem 0.5rem 0.5rem 0.5rem;
  }
}
@media (max-width: 480px) {
  :root {
    --chat--window--width: 100vw;
    --chat--window--height: 100vh;
    --chat--window--bottom: 0;
    --chat--window--right: 0;
    --chat--window--border-radius: 0;
    --chat--message--font-size: 0.91rem;
    --chat--heading--font-size: 1.1rem;
    --chat--subtitle--font-size: 0.85rem;
    --chat--input--font-size: 0.95rem;
    --chat--header--padding: 0.7rem 0.5rem;
    --chat--toggle--size: 56px;
  }
}

