    "Categoría": "Contacto",
    "Enlace": ""
  }
];

const MAX_RESULTS = 3;
const queryText = query?.toLowerCase?.() || "";
const matches = faqs
  .map(faq => {
    let score = 0;
    const pregunta = faq.Pregunta.toLowerCase();
    if (pregunta.includes(queryText)) score += 10;
    queryText.split(" ").forEach(word => {
      if (pregunta.includes(word)) score += 1;
    });
    return { ...faq, score };
  })
  .filter(faq => faq.score > 0)
  .sort((a, b) => b.score - a.score)
  .slice(0, MAX_RESULTS);

if (matches.length > 0) {
  return matches.map(({ Pregunta, Respuesta, Enlace }) => {
    let txt = `• ${Pregunta}\n${Respuesta}`;
    if (Enlace && Enlace.trim() !== "") txt += `\nMás info: ${Enlace}`;
    return txt;
  }).join('\n\n');
}

